import{_ as s,c as e,o as a,a as n}from"./app.6f522281.js";const D=JSON.parse('{"title":"What is VueYoutube?","description":"","frontmatter":{},"headers":[{"level":2,"title":"Motivation","slug":"motivation"},{"level":2,"title":"Improvements over @techassi/vue-youtube-iframe","slug":"improvements-over-techassi-vue-youtube-iframe"},{"level":3,"title":"The Name","slug":"the-name"},{"level":3,"title":"Supports both Vue 2 and 3","slug":"supports-both-vue-2-and-3"},{"level":3,"title":"Supports both Component and Composable Usage","slug":"supports-both-component-and-composable-usage"},{"level":3,"title":"Fully typed","slug":"fully-typed"},{"level":3,"title":"And many smaller Changes","slug":"and-many-smaller-changes"}],"relativePath":"introduction/overview.md"}'),o={name:"introduction/overview.md"},t=n(`<h1 id="what-is-vueyoutube" tabindex="-1">What is VueYoutube? <a class="header-anchor" href="#what-is-vueyoutube" aria-hidden="true">#</a></h1><p>This plugin makes it easy to integrate the YouTube Iframe Player into your Vue 2/3 app.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-hidden="true">#</a></h2><p>I was writing a small Vue application in which I wanted to add an embedded YouTube video. At the time of writing Vue 3 was the new kid on the block and was only released for a short period of time (~ 1-2 months). Naturally I was on the hunt for a Vue plugin which provided access to the YouTube Iframe API as a Component. I found many alternatives on <a href="https://npmjs.com" target="_blank" rel="noopener noreferrer">npmjs.com</a> but all of them were aimed at Vue 2. That&#39;s when I decided to write my own plugin / library which was compatible with the new Vue 3 plugin API and concepts. Out of these efforts <code>@techassi/vue-youtube-iframe</code> was born. <code>@vue-youtube/core</code> is the new and improved iteration under a new name, but from the same author \u{1F603}.</p><h2 id="improvements-over-techassi-vue-youtube-iframe" tabindex="-1">Improvements over @techassi/vue-youtube-iframe <a class="header-anchor" href="#improvements-over-techassi-vue-youtube-iframe" aria-hidden="true">#</a></h2><h3 id="the-name" tabindex="-1">The Name <a class="header-anchor" href="#the-name" aria-hidden="true">#</a></h3><p>The name is much shorter and easier to understand &amp; handle:</p><div class="language-shell"><span class="copy"></span><pre><code><span class="line"><span style="color:#A6ACCD;">@techassi/vue-youtube-iframe</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># vs</span></span>
<span class="line"><span style="color:#A6ACCD;">@vue-youtube/core</span></span>
<span class="line"></span></code></pre></div><h3 id="supports-both-vue-2-and-3" tabindex="-1">Supports both Vue 2 and 3 <a class="header-anchor" href="#supports-both-vue-2-and-3" aria-hidden="true">#</a></h3><p><code>@techassi/vue-youtube-iframe</code> only supported Vue 3 (as this was the initial goal when I wrote the plugin). As mentioned in issue <a href="https://github.com/Techassi/vue-youtube-iframe/issues/4" target="_blank" rel="noopener noreferrer">#4</a> some people requested support for Vue 2 as well. That&#39;s why I added support for both Vue 2 and 3 with the magic of <a href="https://github.com/vueuse/vue-demi" target="_blank" rel="noopener noreferrer">VueDemi</a>. This should work instantly out-of-the-box.</p><h3 id="supports-both-component-and-composable-usage" tabindex="-1">Supports both Component and Composable Usage <a class="header-anchor" href="#supports-both-component-and-composable-usage" aria-hidden="true">#</a></h3><p>One of the biggest improvements is the addition of <a href="https://vuejs.org/guide/reusability/composables.html" target="_blank" rel="noopener noreferrer">Composables</a>. This allows the creation of YouTube Iframe Players with the help of the <code>usePlayer</code> function. This aligns the plugin with Vue 3 coding styles. A sneak peak how you can use the <code>usePlayer</code> function:</p><div class="language-vue"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">script</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">setup</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">lang</span><span style="color:#A6ACCD;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">ts</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">usePlayer</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">@vue-youtube/core</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">ref</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">vue</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> youtube </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">ref</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#82AAFF;">usePlayer</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">dQw4w9WgXcQ</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> youtube)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">ref</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">youtube</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> /&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>For more information see <a href="./getting-started.html">Getting Started</a> and <a href="/docs/usage/composable.html">Usage</a>.</p><h3 id="fully-typed" tabindex="-1">Fully typed <a class="header-anchor" href="#fully-typed" aria-hidden="true">#</a></h3><p>This plugin is completely written in TypeScript and provides strong typings. The <code>@types/youtube</code> package was dropped, but all the player instance types are still available:</p><div class="language-ts"><span class="copy"></span><pre><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> onReady </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">usePlayer</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">dQw4w9WgXcQ</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> youtube)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#82AAFF;">onReady</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">event</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">PlayerEvent</span><span style="color:#89DDFF;">):</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">void</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#A6ACCD;">event</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">target</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">playVideo</span><span style="color:#F07178;">()</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span></code></pre></div><h3 id="and-many-smaller-changes" tabindex="-1">And many smaller Changes <a class="header-anchor" href="#and-many-smaller-changes" aria-hidden="true">#</a></h3><p>A few smaller but still notable changes are:</p><ul><li><strong>Video ID Reactivity:</strong> The video ID is now fully reactive, for both Composables and Components, see here.</li><li><strong>New Events:</strong> Support for the new <code>onPlaybackQualityChange</code>, <code>onPlaybackRateChange</code> and <code>onApiChange</code> events was added. More information about these events can be found <a href="https://developers.google.com/youtube/iframe_api_reference#Events" target="_blank" rel="noopener noreferrer">here</a>.</li><li><strong>New Toolchain:</strong> The plugin now uses the modern <a href="https://vitejs.dev/" target="_blank" rel="noopener noreferrer">Vite</a> Toolchain for both development and production bundling / building.</li></ul>`,20),l=[t];function p(r,c,i,y,u,h){return a(),e("div",null,l)}var F=s(o,[["render",p]]);export{D as __pageData,F as default};
